$outPath = "C:\Users\gg\Downloads\SafeStay\crisisguard-ai\stitch-ui-exports"
if (!(Test-Path -Path $outPath)) {
    New-Item -ItemType Directory -Force -Path $outPath
}

foreach ($key in $screenData.Keys) {
    Write-Host "Downloading $key..."
    $htmlUrl = $screenData[$key].html
    $imgUrl = $screenData[$key].img
    
    $htmlPath = Join-Path -Path $outPath -ChildPath "$key.html"
    $imgPath = Join-Path -Path $outPath -ChildPath "$key.png"
    
    Invoke-WebRequest -Uri $htmlUrl -OutFile $htmlPath
    Invoke-WebRequest -Uri $imgUrl -OutFile $imgPath
}
Write-Host "Done!"
